/*
 * Data Hazard Detection and Forwarding in 5-Stage Pipeline
 * Demonstrates RAW (Read-After-Write) hazards and solution via forwarding
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

// Pipeline Stage Definitions
typedef enum {
 IF, // Instruction Fetch
 ID, // Instruction Decode
 EX, // Execute
 MEM, // Memory Access
 WB // Write Back
} Stage;

// Instruction structure
typedef struct {
 int id;
 char name[10];
 char dest[5];
 char src1[5];
 char src2[5];
 int result; // Computed result
 int executed; // Execution complete flag
} Instruction;

// Pipeline register to hold instruction data between stages
typedef struct {
 Instruction *inst;
 int valid;
 int alu_result; // For forwarding
} PipelineRegister;

// Pipeline state
typedef struct {
 PipelineRegister stages[5]; // IF, ID, EX, MEM, WB
 int clock_cycle;
 int instructions_completed;
} Pipeline;

// Initialize pipeline
void init_pipeline(Pipeline *p) {
 p->clock_cycle = 1;
 p->instructions_completed = 0;
 for (int i = 0; i < 5; i++) {
 p->stages[i].inst = NULL;
 p->stages[i].valid = 0;
 p->stages[i].alu_result = 0;
 }
}

// Check for data hazard (RAW - Read After Write)
int check_data_hazard(Pipeline *p, Instruction *inst) {
 // Check if any previous instruction in pipeline writes to our source register
 for (int i = 0; i < 5; i++) {
 if (p->stages[i].valid && p->stages[i].inst != NULL) {
 // Check EX/MEM and MEM/WB pipeline registers for forwarding
 if (i == EX || i == MEM) {
 // Check if destination matches our source (can forward)
 if (p->stages[i].inst->dest[0] != '\0' && 
 inst->src1[0] != '\0' &&
 strcmp(p->stages[i].inst->dest, inst->src1) == 0) {
 return 1; // Hazard detected - but can forward!
 }
 }
 }
 }
 return 0;
}

// Forward result from previous instruction
int get_forwarded_value(Pipeline *p, char *reg, int from_stage) {
 // In real hardware, forwarding paths come from EX/MEM or MEM/WB registers
 if (from_stage == EX) {
 return p->stages[EX].alu_result; // Forward from EX stage
 }
 return -1; // No forwarding available
}

// Execute one clock cycle
void cycle(Pipeline *p, Instruction *inst_queue, int *queue_idx, int queue_size) {
 printf("\n--- Cycle %d ---\n", p->clock_cycle);

 // Stage 5: Write Back - Complete instruction
 if (p->stages[WB].valid && p->stages[WB].inst != NULL) {
 printf(" [WB] Writing R%d = %d to register file\n", 
 p->stages[WB].inst->id, p->stages[WB].inst->result);
 p->instructions_completed++;
 free(p->stages[WB].inst);
 p->stages[WB].inst = NULL;
 p->stages[WB].valid = 0;
 }

 // Shift stages: MEM -> WB, EX -> MEM, ID -> EX, IF -> ID
 p->stages[WB] = p->stages[MEM];
 p->stages[MEM] = p->stages[EX];

 // Execute stage - perform ALU operation with forwarding
 if (p->stages[EX].valid && p->stages[EX].inst != NULL) {
 int src1_val = 0;
 int src2_val = 0;

 // Check for forwarding from EX or MEM stages
 if (p->stages[MEM].valid && p->stages[MEM].inst != NULL &&
 strcmp(p->stages[MEM].inst->dest, p->stages[EX].inst->src1) == 0) {
 printf(" [FORWARD] Value forwarded from MEM stage\n");
 src1_val = p->stages[MEM].alu_result;
 } else {
 src1_val = 10; // Default register value
 }

 // Simple ALU operation
 if (strncmp(p->stages[EX].inst->name, "ADD", 3) == 0) {
 p->stages[EX].inst->result = src1_val + src2_val;
 p->stages[EX].alu_result = p->stages[EX].inst->result;
 printf(" [EX] ADD: R%d = %d + %d = %d\n", 
 p->stages[EX].inst->id, src1_val, src2_val, p->stages[EX].inst->result);
 }
 p->stages[EX].inst->executed = 1;
 }

 // Decode stage - check for hazards
 if (p->stages[ID].valid && p->stages[ID].inst != NULL) {
 if (check_data_hazard(p, p->stages[ID].inst)) {
 printf(" [ID] Hazard detected! Using forwarding...\n");
 }
 }

 // Fetch new instruction if available
 if (*queue_idx < queue_size) {
 p->stages[IF].inst = (Instruction*)malloc(sizeof(Instruction));
 memcpy(p->stages[IF].inst, &inst_queue[*queue_idx], sizeof(Instruction));
 p->stages[IF].valid = 1;
 printf(" [IF] Fetching instruction: %s\n", p->stages[IF].inst->name);
 (*queue_idx)++;
 } else {
 p->stages[IF].valid = 0;
 }

 p->stages[ID] = p->stages[IF];
 p->stages[EX] = p->stages[ID];

 p->clock_cycle++;
}

// Display pipeline state
void display_pipeline(Pipeline *p) {
 printf("Pipeline State:\n");
 printf(" IF: %s\n", p->stages[IF].valid ? p->stages[IF].inst->name : "-");
 printf(" ID: %s\n", p->stages[ID].valid ? p->stages[ID].inst->name : "-");
 printf(" EX: %s\n", p->stages[EX].valid ? p->stages[EX].inst->name : "-");
 printf(" MEM: %s\n", p->stages[MEM].valid ? p->stages[MEM].inst->name : "-");
 printf(" WB: %s\n", p->stages[WB].valid ? p->stages[WB].inst->name : "-");
}

int main() {
 printf("============================================\n");
 printf(" 5-Stage Pipeline: Data Hazard & Forwarding\n");
 printf("============================================\n");

 // Create instruction queue with data dependency
 // ADD writes to R1, SUB reads from R1 - RAW hazard!
 Instruction instructions[] = {
 {1, "ADD", "R1", "R2", "R3", 0, 0},
 {2, "SUB", "R4", "R1", "R5", 0, 0},
 {3, "AND", "R5", "R4", "R6", 0, 0}
 };

 int num_instructions = 3;
 int queue_idx = 0;

 Pipeline pipeline;
 init_pipeline(&pipeline);

 // Run pipeline until all instructions complete
 int completed = 0;
 int max_cycles = 20;

 while (completed < num_instructions && max_cycles-- > 0) {
 cycle(&pipeline, instructions, &queue_idx, num_instructions);

 // Count completed instructions (in WB stage completing)
 if (pipeline.stages[WB].valid == 0 && pipeline.stages[MEM].valid == 0 &&
 pipeline.stages[EX].valid == 0) {
 completed++;
 }
 }

 printf("\n============================================\n");
 printf("PIPELINE EXECUTION COMPLETE\n");
 printf("============================================\n");
 printf("Total Cycles: %d\n", pipeline.clock_cycle - 1);
 printf("Instructions Completed: %d\n", pipeline.instructions_completed);
 printf("Speedup vs Non-Pipelined: %.2fx\n", 
 (num_instructions * 5.0) / (pipeline.clock_cycle - 1));

 return 0;
}
